  fullWidth
  label="WhatsApp"
  name="whatsapp"
  value={formData.whatsapp}
  onChange={handleChange}
/>

// NEW:
<PhoneInput
  label="WhatsApp"
  value={formData.whatsapp}
  countryCode={formData.whatsapp_country}
  onChange={(phone, countryCode) => {
    setFormData(prev => ({
      ...prev,
      whatsapp: phone,
      whatsapp_country: countryCode,
    }));
  }}
  defaultCountryCode={formData.whatsapp_country}
/>
```

**4. Update API Payload:**
API submission already includes all formData fields, so country code fields will be sent automatically.

